const express = require('express');
const fs = require('fs');
const path = require('path');
const morgan = require('morgan');
const winston = require('winston');

const app = express();

app.use(express.json({ limit: '1mb' }));
app.use(express.urlencoded({ extended: true }));

const logDir = path.join(__dirname, 'logs');
fs.mkdirSync(logDir, { recursive: true });

const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.printf(({ timestamp, level, message }) => `${timestamp} ${level.toUpperCase()} ${message}`)
  ),
  transports: [
    new winston.transports.File({ filename: path.join(logDir, 'audit.log') }),
    new winston.transports.File({ filename: path.join(logDir, 'error.log'), level: 'error' })
  ]
});

morgan.token('username', (req) => (req.body && req.body.username) || req.query.username || req.headers['x-username'] || 'anonymous');
morgan.token('ip', (req) => req.headers['x-forwarded-for'] || req.socket.remoteAddress || '-');
morgan.token('custom', (req) => req.headers['x-custom-header'] || '-');
morgan.token('ua', (req) => req.headers['user-agent'] || '-');

app.use(
  morgan(':date[iso] :method :url :status :res[content-length] - :response-time ms user=:username ip=:ip custom=:custom ua=":ua"', {
    stream: {
      write: (line) => auditLogger.info(line.trim())
    }
  })
);

app.post('/login', (req, res) => {
  const username = req.body.username || 'anonymous';
  const ip = req.headers['x-forwarded-for'] || req.socket.remoteAddress || '-';
  const customHeader = req.headers['x-custom-header'] || '-';
  auditLogger.info(`LOGIN_ATTEMPT username=${username} ip=${ip} x-custom-header=${customHeader} body=${JSON.stringify(req.body)} headers=${JSON.stringify(req.headers)}`);
  res.json({ ok: true });
});

app.post('/audit', (req, res) => {
  const username = req.body.username || req.query.username || req.headers['x-username'] || 'anonymous';
  const ip = req.headers['x-forwarded-for'] || req.socket.remoteAddress || '-';
  const event = req.body.event || req.query.event || 'custom_event';
  const details = req.body.details || req.query.details || req.body || req.query;

  auditLogger.info(`AUDIT_EVENT user=${username} ip=${ip} event=${event} details=${typeof details === 'string' ? details : JSON.stringify(details)} headers=${JSON.stringify(req.headers)}`);
  res.json({ ok: true });
});

app.post('/echo', (req, res) => {
  auditLogger.info(`ECHO body=${JSON.stringify(req.body)} query=${JSON.stringify(req.query)} headers=${JSON.stringify(req.headers)}`);
  res.json({ ok: true, body: req.body, query: req.query });
});

app.use((err, req, res, next) => {
  auditLogger.error(`ERROR ${err && err.stack ? err.stack : String(err)} body=${JSON.stringify(req.body)} headers=${JSON.stringify(req.headers)}`);
  res.status(500).json({ ok: false, error: 'internal_error' });
});

const port = process.env.PORT || 3000;
app.listen(port, () => {
  auditLogger.info(`Server listening on port ${port}`);
});